import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import api from '../services/api';
import Cronometro from '../components/Cronometro';
import UploadFotos from '../components/UploadFotos';

function NovaOS() {
    const navigate = useNavigate();
    const [clientes, setClientes] = useState([]);
    const [categorias, setCategorias] = useState([]);
    const [osId, setOsId] = useState(null); // ID após criar
    const [form, setForm] = useState({
        cliente_id: '',
        categoria_id: '',
        numero_os: '',
        equipamento: '',
        modelo: '',
        imei: '',
        defeito: '',
        tipo_atendimento: 'presencial',
        estimativa_horas: '',
        preco_final: ''
    });
    const [servicoRealizado, setServicoRealizado] = useState('');
    const [statusOs, setStatusOs] = useState('aberto');

    // Carregar clientes e categorias
    useEffect(() => {
        const load = async () => {
            const clientesRes = await api.get('/clientes');
            setClientes(clientesRes.data);
            const catRes = await api.get('/categorias');
            setCategorias(catRes.data);
        };
        load();
    }, []);

    // Gerar número da OS automaticamente (ex: 20260001)
    const gerarNumeroOS = () => {
        const ano = new Date().getFullYear();
        return `${ano}${String(Math.floor(Math.random() * 10000)).padStart(4, '0')}`;
    };

    // Quando selecionar categoria, preenche preço e estimativa
    useEffect(() => {
        if (form.categoria_id) {
            const cat = categorias.find(c => c.id === parseInt(form.categoria_id));
            if (cat) {
                setForm(prev => ({
                    ...prev,
                    preco_final: cat.preco_sugerido || '',
                    estimativa_horas: cat.tempo_estimado_minutos ? (cat.tempo_estimado_minutos / 60).toFixed(2) : ''
                }));
            }
        }
    }, [form.categoria_id, categorias]);

    const handleChange = (e) => {
        setForm({ ...form, [e.target.name]: e.target.value });
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        if (!form.cliente_id) return alert('Selecione um cliente');
        const novaOS = {
            ...form,
            numero_os: gerarNumeroOS(),
            estimativa_horas: form.estimativa_horas ? parseFloat(form.estimativa_horas) : null,
            preco_final: form.preco_final ? parseFloat(form.preco_final) : null
        };
        try {
            const res = await api.post('/os', novaOS);
            setOsId(res.data.id);
            alert('OS criada com sucesso! Agora você pode iniciar o cronômetro e anexar fotos.');
        } catch (err) {
            alert('Erro ao criar OS: ' + err.response?.data?.error);
        }
    };

    const handleSalvarServico = async () => {
        if (!osId) return;
        try {
            await api.put(`/os/${osId}`, { servico_realizado: servicoRealizado, status_os: statusOs });
            alert('Serviço e status atualizados');
        } catch (err) {
            alert('Erro ao atualizar');
        }
    };

    if (osId) {
        return (
            <div>
                <h2>OS #{osId} em andamento</h2>
                <Cronometro osId={osId} />
                <UploadFotos osId={osId} />
                <div style={{ marginTop: '20px' }}>
                    <label>Serviço realizado (o que foi feito):</label><br />
                    <textarea rows="4" cols="50" value={servicoRealizado} onChange={e => setServicoRealizado(e.target.value)} style={{ width: '100%' }} />
                </div>
                <div>
                    <label>Status da OS:</label>
                    <select value={statusOs} onChange={e => setStatusOs(e.target.value)}>
                        <option value="aberto">Aberto</option>
                        <option value="analise">Em análise</option>
                        <option value="aguardando_peca">Aguardando peça</option>
                        <option value="concluido">Concluído</option>
                        <option value="entregue">Entregue</option>
                    </select>
                </div>
                <button onClick={handleSalvarServico}>Salvar serviço e status</button>
                <button onClick={() => navigate('/')}>Voltar à Home</button>
            </div>
        );
    }

    return (
        <div>
            <h2>Nova Ordem de Serviço</h2>
            <form onSubmit={handleSubmit}>
                <div>
                    <label>Cliente *</label>
                    <select name="cliente_id" value={form.cliente_id} onChange={handleChange} required>
                        <option value="">Selecione</option>
                        {clientes.map(c => <option key={c.id} value={c.id}>{c.nome}</option>)}
                    </select>
                </div>
                <div>
                    <label>Categoria</label>
                    <select name="categoria_id" value={form.categoria_id} onChange={handleChange}>
                        <option value="">Selecione</option>
                        {categorias.map(c => <option key={c.id} value={c.id}>{c.nome}</option>)}
                    </select>
                </div>
                <div>
                    <label>Equipamento</label>
                    <input type="text" name="equipamento" value={form.equipamento} onChange={handleChange} />
                </div>
                <div>
                    <label>Modelo</label>
                    <input type="text" name="modelo" value={form.modelo} onChange={handleChange} />
                </div>
                <div>
                    <label>IMEI (para celular)</label>
                    <input type="text" name="imei" value={form.imei} onChange={handleChange} />
                </div>
                <div>
                    <label>Defeito relatado</label>
                    <textarea name="defeito" value={form.defeito} onChange={handleChange} rows="3" style={{ width: '100%' }} />
                </div>
                <div>
                    <label>Tipo de atendimento</label>
                    <select name="tipo_atendimento" value={form.tipo_atendimento} onChange={handleChange}>
                        <option value="presencial">Presencial</option>
                        <option value="remoto">Remoto</option>
                    </select>
                </div>
                <div>
                    <label>Estimativa (horas)</label>
                    <input type="number" step="0.5" name="estimativa_horas" value={form.estimativa_horas} onChange={handleChange} />
                </div>
                <div>
                    <label>Preço final (R$)</label>
                    <input type="number" step="0.01" name="preco_final" value={form.preco_final} onChange={handleChange} />
                </div>
                <button type="submit">Criar OS</button>
            </form>
        </div>
    );
}

export default NovaOS;
